mapper.select:
SELECT GROUP_CD AS groupCd, DETAIL_CD AS detailCd, DETAIL_NM AS detailNm, USE_YN AS useYn FROM mhdb.TB_CODE_DETAIL WHERE GROUP_CD = #{groupCd}
AND DETAIL_CD = #{detailCd}
ORDER BY DETAIL_CD

SELECT GROUP_CD AS groupCd, DETAIL_CD AS detailCd, DETAIL_NM AS detailNm, USE_YN AS useYn FROM mhdb.TB_CODE_DETAIL WHERE GROUP_CD = #{groupCd}
AND USE_YN LIKE concat('%', #{useYn}, '%')
ORDER BY DETAIL_CD

mapper.update:
UPDATE mhdb.TB_CODE_GROUP
SET GROUP_NM = #{groupNm},
	USE_YN = #{useYn}
WHERE GROUP_CD = #{groupCd}

UPDATE mhdb.TB_CODE_DETAIL
SET DETAIL_NM = #{detailNm},
	USE_YN = #{useYn}
WHERE GROUP_CD = #{groupCd}
  AND DETAIL_CD = #{detailCd}

mapper.delete:
DELETE FROM mhdb.TB_CODE_DETAIL
WHERE GROUP_CD = #{groupCd}
  AND DETAIL_CD = #{detailCd}
